mapper.select:
SELECT * FROM kodik_content_enrichment
WHERE content_id = #{contentId}
ORDER BY source

SELECT c.id FROM kodik_content c
LEFT JOIN kodik_content_enrichment e
       ON e.content_id = c.id AND e.source = #{source}
WHERE e.id IS NULL
   OR e.last_refreshed_at < #{olderThan}
ORDER BY c.id
LIMIT #{limit}
